export interface RpcRequest {
  id: string;
  action: string;
  params?: Record<string, unknown>;
}

export interface RpcError {
  code: number;
  message: string;
  data: unknown | null;
}

export interface RpcResponse {
  id: string;
  result?: unknown;
  error?: RpcError | null;
}

export interface WsEvent {
  event: string;
  payload: Record<string, unknown>;
}

export interface SessionMessage {
  id: string;
  role: "user" | "assistant" | "tool" | "system";
  content: string;
  timestamp: number;
}

export interface SessionTurn {
  turnId: string;
  userInput: string;
  assistantOutput: string;
  createdAt: number;
  files: string[];
}

export type SessionState = "idle" | "processing" | "error";

export interface Session {
  sessionId: string;
  sessionName: string;
  agentType: string;
  state: SessionState;
  turnCount: number;
  createdAt: number;
  workspacePath?: string;
  messages: SessionMessage[];
  turns: SessionTurn[];
}

export interface AIModelConfig {
  id: string;
  name: string;
  provider: string;
  model_name: string;
  base_url?: string;
  api_key?: string;
  context_window?: number;
  max_tokens?: number;
  enabled?: boolean;
  enable_thinking_process?: boolean;
  support_preserved_thinking?: boolean;
  custom_headers?: Record<string, string>;
  custom_headers_mode?: string;
  skip_ssl_verify?: boolean;
  custom_request_body?: string;
}

export interface ModeConfig {
  mode_id: string;
  available_tools: string[];
  enabled: boolean;
  default_tools: string[];
}

export interface ConfigState {
  values: Record<string, unknown>;
  modelConfigs: AIModelConfig[];
  modeConfigs: Record<string, ModeConfig>;
  subagentConfigs: Record<string, { enabled: boolean }>;
  mcpServers: Array<{
    id: string;
    name: string;
    status: string;
    serverType: string;
    enabled: boolean;
    autoStart: boolean;
  }>;
}
